import math

def solution(n_limit: int = 100, threshold: int = 1000000) -> int:
    """
    Optimized count using symmetry property nCr = nC(n-r).
    """
    total_count = 0
    for n in range(23, n_limit + 1):
        # For each n, find the first r such that nCr > threshold
        for r in range(2, n // 2 + 1):
            if math.comb(n, r) > threshold:
                # All values between r and n-r will also be > threshold
                total_count += (n - 2 * r + 1)
                break
    return total_count


if __name__ == "__main__":
    print(solution())
